#include <zephyr.h>

#include <sys/printk.h>
#include <sys/device.h>

#include <drivers/flash/qspi_nor.h>

#define FLASH_DEV_NAME "qspi_nor0"

static void flash_write(const char *data, size_t len)
{
    struct device *dev = DEVICE_DT_GET(FLASH_DEV_NAME);

    if (flash_erase_page(dev, 0x100000)) {
        printk("erase error\n");
    } else {
        printk("erased page 0x%x\n", FLASH_PAGE_SIZE + 0x100000);

        if (flash_write(dev, 0x100000, data, len)) {
            printk("write error\n");
        } else {
            printk("wrote %d bytes at page 0x%x\n", len, FLASH_PAGE_SIZE + 0x100000);
        }
    }
}

static void main(void)
{
    flash_write("Hello World!\n", sizeof("Hello World!"));

    printk("done\n");
}